// Capture everything from Airtable record in ONE place
const record = $json;
return {
  json: {
    RECORD_ID: record.id,
    company_name: record['Company Name'] || '',
    company_url: record['Company URL'] || '',
    description: record['Company Description'] || '',
    source: record['VC Firm'] || record['Source'] || 'Rescore',
    existing_dq_reasons: record['Disqualify Reasons'] || '',
    searchQuery: '"' + (record['Company Name'] || '') + '" company funding employees series startup'
  }
};

const captured = $('Capture').first().json;
const RECORD_ID = captured.RECORD_ID;
const company_name = captured.company_name;
const company_url = captured.company_url;
const description = captured.description;
const source = captured.source;
const existing_dq_reasons = captured.existing_dq_reasons || '';

const braveResponse = $json;
const searchResults = braveResponse?.web?.results || [];
const allText = searchResults.map(r => (r.title || '') + ' ' + (r.description || '')).join(' ');

const peFirms = ['Vista Equity', 'Thoma Bravo', 'KKR', 'Blackstone', 'TPG', 'Carlyle', 'Bain Capital', 'Silver Lake', 'Francisco Partners', 'Insight Partners', 'Clearlake', 'Welsh Carson', 'General Atlantic', 'Warburg Pincus', 'Apollo', 'TA Associates', 'Brighton Park Capital', 'Summit Partners', 'SoftBank Vision Fund', 'EQT Partners', 'Permira', 'Hellman & Friedman', 'Advent', 'Providence Equity'];

let employeeCount = null;
const empMatch = allText.match(/(\d[\d,]*)\s*(?:to\s*[\d,]+)?\s*employees?/i);
if (empMatch) employeeCount = parseInt(empMatch[1].replace(/,/g, ''));

let fundingStage = null;
if (/Series\s*D/i.test(allText)) fundingStage = 'Series D';
else if (/Series\s*C/i.test(allText)) fundingStage = 'Series C';
else if (/Series\s*B/i.test(allText)) fundingStage = 'Series B';
else if (/Series\s*A/i.test(allText)) fundingStage = 'Series A';
else if (/\bSeed\b/i.test(allText)) fundingStage = 'Seed';

let totalFundingRaw = null;
const fundingMatch = allText.match(/(?:raised|funding|round)\s*\$([\d.]+)\s*(million|billion|M|B)/i);
if (fundingMatch) {
  const amt = parseFloat(fundingMatch[1]);
  const u = fundingMatch[2].toLowerCase();
  const val = (u === 'billion' || u === 'b') ? amt * 1000 : amt;
  totalFundingRaw = val >= 1000 ? '$' + (val/1000).toFixed(1) + 'B' : '$' + val.toFixed(1) + 'M';
}

const isPEBacked = peFirms.some(f => new RegExp(f, 'i').test(allText));

let foundedYear = null;
const foundMatch = allText.match(/(?:founded|established|since)\s*(?:in)?\s*(\d{4})/i);
if (foundMatch) foundedYear = parseInt(foundMatch[1]);

const isAcquired = /\b(acquired|was acquired|acquisition|merged with|bought by|shut down|defunct)\b/i.test(allText);
const isPublic = /\b(NYSE|NASDAQ|publicly traded|IPO|went public)\b/i.test(allText);
const isBiotech = /\b(therapeutic|drug development|clinical trial|pharma|biotech)\b/i.test(allText);
const isHardware = /\b(hardware|sensors|devices|robotics|manufacturing|semiconductor)\b/i.test(allText) && !/\bSaaS\b/i.test(allText);
const isCrypto = /\b(blockchain|cryptocurrency|web3|NFT|DeFi)\b/i.test(allText);
const isConsumer = /\b(consumer app|DTC|direct-to-consumer|B2C|telehealth)\b/i.test(allText);

// v4.1: Check for existing disqualify reasons - don't let bad Brave data override previous DQ
const disqualifiers = [];
if (existing_dq_reasons.length > 0) disqualifiers.push('Pre-existing DQ: ' + existing_dq_reasons);
if (isAcquired) disqualifiers.push('Acquired');
if (isPEBacked) disqualifiers.push('PE-backed');
if (employeeCount && employeeCount > 200) disqualifiers.push('Too large (' + employeeCount + ' employees)');
if (isPublic) disqualifiers.push('Public company');
if (fundingStage === 'Series D') disqualifiers.push('Late stage (Series D)');
if (isBiotech) disqualifiers.push('Biotech/pharma');
if (isHardware) disqualifiers.push('Hardware');
if (isCrypto) disqualifiers.push('Crypto/Web3');
if (isConsumer) disqualifiers.push('Consumer/B2C');
if (employeeCount && employeeCount < 15) disqualifiers.push('Too early (' + employeeCount + ' employees)');

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: company_name,
    company_url: company_url,
    description: description,
    source: source,
    funding_stage: fundingStage,
    total_funding: totalFundingRaw,
    employee_count: employeeCount,
    pe_backed: isPEBacked,
    founded_year: foundedYear,
    disqualify_reasons: disqualifiers.join('; '),
    isAutoDisqualified: disqualifiers.length > 0
  }
};

const c = $json;
return {
  json: {
    RECORD_ID: c.RECORD_ID,
    company_name: c.company_name,
    company_url: c.company_url,
    description: c.description,
    source: c.source,
    funding_stage: c.funding_stage,
    total_funding: c.total_funding,
    employee_count: c.employee_count,
    pe_backed: c.pe_backed,
    founded_year: c.founded_year,
    personaPrompt: 'Company: ' + c.company_name + '. Description: ' + (c.description || 'No description') + '. URL: ' + (c.company_url || 'N/A') + '. Classify as business-user, developer, or mixed. Respond with ONE word only.'
  }
};

const prev = $('Build Persona').first().json;
const RECORD_ID = prev.RECORD_ID;

const response = $json;
let persona = 'unknown';
try {
  const content = response.content?.[0]?.text || '';
  const clean = content.toLowerCase().trim();
  if (clean.includes('business')) persona = 'business-user';
  else if (clean.includes('developer')) persona = 'developer';
  else if (clean.includes('mixed')) persona = 'mixed';
} catch (e) {}

const employeeCount = prev.employee_count || 0;
const shouldAutoPass = persona === 'developer' && employeeCount < 50;

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: prev.company_name,
    company_url: prev.company_url,
    description: prev.description,
    source: prev.source,
    funding_stage: prev.funding_stage,
    total_funding: prev.total_funding,
    employee_count: prev.employee_count,
    pe_backed: prev.pe_backed,
    founded_year: prev.founded_year,
    customer_persona: persona,
    developer_auto_pass: shouldAutoPass
  }
};

