const c = $json;
const evalPrompt = 'COMPANY: ' + c.company_name + '. URL: ' + c.company_url + '. Description: ' + c.description + '. Funding: ' + (c.funding_stage || 'Unknown') + '. Employees: ' + (c.employee_count || 'Unknown') + '. Persona: ' + c.customer_persona + '. Score 0-100 for job search fit. Return JSON: {"bucket":"APPLY|WATCH|PASS","total_score":N,"sector_match":"target|adjacent|unrelated","cs_hire_likelihood":"high|medium|low","product_type":"enterprise|mid-market|self-serve","summary":"2 sentences"}';

return {
  json: {
    RECORD_ID: c.RECORD_ID,
    company_name: c.company_name,
    funding_stage: c.funding_stage,
    total_funding: c.total_funding,
    employee_count: c.employee_count,
    pe_backed: c.pe_backed,
    founded_year: c.founded_year,
    customer_persona: c.customer_persona,
    evalPrompt: evalPrompt
  }
};

const prev = $('Build Eval').first().json;
const RECORD_ID = prev.RECORD_ID;

const response = $json;
let evaluation = { bucket: 'WATCH', total_score: 0, summary: 'Parse error' };
try {
  const content = response.content?.[0]?.text || '';
  const jsonMatch = content.match(/\{[\s\S]*\}/);
  if (jsonMatch) evaluation = JSON.parse(jsonMatch[0]);
} catch (e) {}

const statusMap = { 'APPLY': 'Apply', 'WATCH': 'Monitor', 'PASS': 'Skip' };
const nextStepsMap = { 'APPLY': 'Apply Now', 'WATCH': 'Watch for Jobs', 'PASS': 'Skip' };

return {
  json: {
    RECORD_ID: RECORD_ID,
    company_name: prev.company_name,
    status: statusMap[evaluation.bucket] || 'Research',
    next_steps: nextStepsMap[evaluation.bucket] || 'Research More',
    total_score: evaluation.total_score || 0,
    sector_match: evaluation.sector_match || 'unknown',
    cs_hire_likelihood: evaluation.cs_hire_likelihood || '',
    product_type: evaluation.product_type || '',
    summary: evaluation.summary || '',
    funding_stage: prev.funding_stage,
    total_funding: prev.total_funding,
    employee_count: prev.employee_count,
    pe_backed: prev.pe_backed,
    founded_year: prev.founded_year,
    customer_persona: prev.customer_persona
  }
};
